#include <stdio.h>

int findKthPositive(const int *nums, int n, int k) {
    for (int i = 0; i < n; ++i) {
        int missing = nums[i] - (i + 1);
        if (missing >= k) {
            return k + i;
        }
    }
    return k + n;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, k; scanf("%d %d", &N, &k);
        int nums[1005]; // N <= 1000
        for (int i = 0; i < N; ++i) scanf("%d", &nums[i]);
        printf("%d\n", findKthPositive(nums, N, k));
    }
    return 0;
}

