import sys

def find_kth(nums, k):
    for i, val in enumerate(nums):
        missing = val - (i + 1)
        if missing >= k:
            return k + i
    return k + len(nums)

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        k = int(next(it))
        nums = [int(next(it)) for _ in range(N)]
        out.append(str(find_kth(nums, k)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

